// src/services/greeting.service.js
const getGreetingMessage = () => {
  return { message: 'Hello from Service!' };
};
module.exports = { getGreetingMessage };

// src/controllers/greeting.controller.js
const greetingService = require('../services/greeting.service');
const sayHello = (req, res) => {
  const data = greetingService.getGreetingMessage();
  res.status(200).json(data);
};
module.exports = { sayHello };
